VALUES
  ('optometrist-moex-01254', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '鏡框製作過程中要注意患者配戴眼鏡時，通常會使患者眼睛產生稜鏡效應現象，因此鏡框製作過程光學鏡 片在裝配鏡框上會產生水平或垂直稜鏡的現象，這樣垂直稜鏡些許的誤差值在患者眼睛內是不一定可被接 受；若垂直稜鏡誤差值過大，超出下列何種範圍的標準是不可以被接受的？', '["主要參考點位置的垂直距離小於1.0mm或垂直稜鏡超過0.33Δ", "主要參考點位置的垂直距離小於1.0mm且垂直稜鏡超過0.67Δ", "主要參考點位置的垂直距離大於1.0mm且垂直稜鏡超過0.33Δ", "主要參考點位置的垂直距離大於1.0mm或垂直稜鏡超過0.67Δ"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01255', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有一患者配戴眼鏡，其處方右眼OD：-3.00DS有2Δ，左眼OS：-1.00DS有3.5Δ，雙眼各別將使距離4m 的物像產生多少位移？', '["右眼位移6cm，左眼位移3.5cm", "右眼位移24cm，左眼位移3.5cm", "右眼位移1.5cm，左眼位移0.875cm", "右眼位移8cm，左眼位移14cm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01256', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '當一患者的右眼度數為 OD：-2.00DS/-1.00DC×180，左眼度數為 OS：-3.50 DS，若主要參考點（major referencepoint,MRP）上的高度是26mm，鏡框垂直尺寸（B-box）為50mm，則主要參考點上的位移量是 多少？', '["0.5mm", "2mm", "1mm", "3mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01257', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '維修眼鏡時，欲移除斷裂或卡在桶狀部（barrel）的螺絲，不應使用下列何種方法？', '["將塑膠鏡架的端片浸入丙酮，然後試著以螺絲起子移除卡住的螺絲", "使用滲透油將螺絲鬆脫，再試著以螺絲起子移除卡住的螺絲", "在凸出於桶狀部之外的斷裂螺絲殘留尖端上，銼磨一個給螺絲起子用的新開槽，再以螺絲起子移除螺絲 殘留部分", "使用打孔鉗以移除螺絲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01258', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '在頂點距離為7mm的條件下眼鏡處方度數為-10.00DS，若頂點距離為12mm，再配製一副眼鏡，則此眼 鏡處方度數最接近下列何者？', '["-10.25DS", "-10.50DS", "-11.00DS", "-11.50DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01259', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '某君的眼鏡正常遠用和近用處方，右眼為+1.25DS/-0.75DC×175，加入度為+2.00 D，若其選擇1.00D度 數範圍（遞減）的近用型變焦鏡片，則右眼鏡片上半部的度數將為何？', '["+2.00DS/-0.75DC×175", "+2.25DS/-0.75DC×175", "+2.50DS/-0.75DC×175", "+2.75DS/-0.75DC×175"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01260', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有一鏡架具有以下尺寸之規格：A（box）＝48mm、C（box）＝50mm、DBL＝19mm、子片降距＝4mm、 子片高度＝21.5mm，則B尺寸為何？', '["50mm", "51mm", "52mm", "53mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01261', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列遠視型不等視的眼鏡設計，何者最不適當？', '["鏡框的眼型尺寸選擇比較小的", "比較高的正度數要減少頂點距離", "比較高的正度數要增加中心厚度", "比較低的正度數要比較陡的基弧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01262', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '依Knapp’slaw為基礎，下列那種不等視者，用框架眼鏡時，其兩眼影像不等的情況比較小？', '["屈光性近視", "軸性近視", "屈光性遠視", "散光型不等視"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01263', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配製漸進多焦點鏡片（progressiveadditionlenses）的鏡框，建議其適合的前傾角（pantoscopictilt）範圍為何？', '["4°～6°", "7°～9°", "10°～12°", "13°～15°"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
